import React, { useState } from 'react';
import API from '../api/axios';
import { useNavigate, Link } from 'react-router-dom';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [errorMessage, setErrorMessage] = useState('');
    const [isForgotPassword, setIsForgotPassword] = useState(false);
    const [forgotPasswordEmail, setForgotPasswordEmail] = useState('');
    const [forgotPasswordLoading, setForgotPasswordLoading] = useState(false);
    const [forgotPasswordMessage, setForgotPasswordMessage] = useState('');
    const [forgotPasswordError, setForgotPasswordError] = useState('');

    const navigate = useNavigate();

    // ============ LOGIN FUNCTION ============
    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        setErrorMessage('');

        try {
            console.log('🔐 Attempting login with:', { email, password });
            const { data } = await API.post('/auth/login', { email, password });

            // Store user data
            localStorage.setItem('token', data.token);
            localStorage.setItem('role', data.role);
            localStorage.setItem('userName', data.userName || email.split('@')[0] || 'User');
            localStorage.setItem('userId', data.userId);
            localStorage.setItem('userEmail', email);

            console.log('✅ Login successful! Token received:', data.token?.substring(0, 20) + '...');
            console.log('👤 User Role:', data.role);
            console.log('👤 User Name:', data.userName);

            // Simulate loading for better UX
            setTimeout(() => {
                navigate('/dashboard');
            }, 500);

        } catch (err) {
            const message = err.response?.data?.message || "Invalid email or password";
            setErrorMessage(message);
            console.error('❌ Login error:', message);
            console.error('📋 Error details:', err.response?.data || err.message);
        } finally {
            setLoading(false);
        }
    };

    // ============ FORGOT PASSWORD FUNCTION ============
    const handleForgotPassword = async (e) => {
        e.preventDefault();
        setForgotPasswordLoading(true);
        setForgotPasswordError('');
        setForgotPasswordMessage('');

        if (!forgotPasswordEmail) {
            setForgotPasswordError('Please enter your email address');
            setForgotPasswordLoading(false);
            return;
        }

        try {
            console.log('📧 Sending password reset request for:', forgotPasswordEmail);

            // In a real app, this would be an API call
            // const { data } = await API.post('/auth/forgot-password', { email: forgotPasswordEmail });

            // Simulate API call
            setTimeout(() => {
                console.log('✅ Password reset link sent to:', forgotPasswordEmail);
                console.log('📋 Reset link: http://localhost:3000/reset-password?token=temp_reset_token_12345');

                setForgotPasswordMessage(`Password reset link has been sent to ${forgotPasswordEmail}. 
Check your inbox and follow the instructions.`);

                // Clear the email field
                setForgotPasswordEmail('');

                // Auto-close forgot password modal after 5 seconds
                setTimeout(() => {
                    setIsForgotPassword(false);
                    setForgotPasswordMessage('');
                }, 5000);
            }, 1500);

        } catch (err) {
            const message = err.response?.data?.message || "Failed to send reset link. Please try again.";
            setForgotPasswordError(message);
            console.error('❌ Forgot password error:', message);
        } finally {
            setForgotPasswordLoading(false);
        }
    };

    // ============ GOOGLE LOGIN FUNCTION ============
    const handleGoogleLogin = async () => {
        console.log('🌐 Attempting Google OAuth login...');

        // In a real app, this would redirect to Google OAuth
        // window.location.href = 'https://accounts.google.com/o/oauth2/auth?client_id=YOUR_CLIENT_ID&redirect_uri=YOUR_REDIRECT_URI&response_type=code&scope=email%20profile';

        // For demo purposes, simulate Google login
        setLoading(true);
        setTimeout(() => {
            console.log('✅ Google login successful!');
            console.log('👤 Simulating Google user: john.doe@gmail.com');

            // Store dummy Google user data
            localStorage.setItem('token', 'google_dummy_token_12345');
            localStorage.setItem('role', 'user');
            localStorage.setItem('userName', 'John Doe');
            localStorage.setItem('userId', 'google_12345');
            localStorage.setItem('userEmail', 'john.doe@gmail.com');
            localStorage.setItem('authProvider', 'google');

            setLoading(false);
            navigate('/dashboard');
        }, 1500);
    };

    // ============ LINKEDIN LOGIN FUNCTION ============
    const handleLinkedInLogin = async () => {
        console.log('💼 Attempting LinkedIn OAuth login...');

        // In a real app, this would redirect to LinkedIn OAuth
        // window.location.href = 'https://www.linkedin.com/oauth/v2/authorization?response_type=code&client_id=YOUR_CLIENT_ID&redirect_uri=YOUR_REDIRECT_URI&scope=r_liteprofile%20r_emailaddress';

        // For demo purposes, simulate LinkedIn login
        setLoading(true);
        setTimeout(() => {
            console.log('✅ LinkedIn login successful!');
            console.log('👤 Simulating LinkedIn user: johndoe@company.com');

            // Store dummy LinkedIn user data
            localStorage.setItem('token', 'linkedin_dummy_token_67890');
            localStorage.setItem('role', 'user');
            localStorage.setItem('userName', 'John Doe (LinkedIn)');
            localStorage.setItem('userId', 'linkedin_67890');
            localStorage.setItem('userEmail', 'johndoe@company.com');
            localStorage.setItem('authProvider', 'linkedin');

            setLoading(false);
            navigate('/dashboard');
        }, 1500);
    };

    // ============ DEMO LOGIN FUNCTION ============
    const handleDemoLogin = () => {
        console.log('🎮 Using demo account...');
        setEmail('demo@example.com');
        setPassword('demo123');

        // Auto-submit after setting demo credentials
        setTimeout(() => {
            const demoEvent = { preventDefault: () => {} };
            setLoading(true);
            setTimeout(() => {
                handleLogin(demoEvent);
            }, 500);
        }, 100);
    };

    return (
        <div style={styles.container}>
            <div style={styles.loginCard}>
                {/* Header */}
                <div style={styles.header}>
                    <h1 style={styles.title}>Welcome</h1>
                    <p style={styles.subtitle}>Sign into your account.</p>
                </div>

                {/* Forgot Password Modal */}
                {isForgotPassword && (
                    <div style={styles.modalOverlay}>
                        <div style={styles.modalContent}>
                            <div style={styles.modalHeader}>
                                <h3 style={styles.modalTitle}>Reset Password</h3>
                                <button 
                                    onClick={() => setIsForgotPassword(false)}
                                    style={styles.modalClose}
                                >
                                    ×
                                </button>
                            </div>

                            <form onSubmit={handleForgotPassword} style={styles.modalForm}>
                                <p style={styles.modalText}>
                                    Enter your email address and we'll send you a link to reset your password.
                                </p>

                                <input
                                    type="email"
                                    placeholder="Enter your email"
                                    value={forgotPasswordEmail}
                                    onChange={(e) => setForgotPasswordEmail(e.target.value)}
                                    style={styles.modalInput}
                                    required
                                    disabled={forgotPasswordLoading}
                                />

                                {forgotPasswordError && (
                                    <div style={styles.errorMessage}>
                                        ⚠️ {forgotPasswordError}
                                    </div>
                                )}

                                {forgotPasswordMessage && (
                                    <div style={styles.successMessage}>
                                        ✅ {forgotPasswordMessage}
                                    </div>
                                )}

                                <div style={styles.modalButtons}>
                                    <button
                                        type="button"
                                        onClick={() => setIsForgotPassword(false)}
                                        style={styles.modalSecondaryButton}
                                        disabled={forgotPasswordLoading}
                                    >
                                        Cancel
                                    </button>
                                    <button
                                        type="submit"
                                        style={styles.modalPrimaryButton}
                                        disabled={forgotPasswordLoading}
                                    >
                                        {forgotPasswordLoading ? 'Sending...' : 'Send Reset Link'}
                                    </button>
                                </div>
                            </form>
                        </div>
                    </div>
                )}

                {/* Login Form */}
                <form onSubmit={handleLogin} style={styles.form}>
                    {/* Email Input */}
                    <div style={styles.inputGroup}>
                        <label style={styles.label}>Email</label>
                        <input
                            type="email"
                            style={styles.input}
                            placeholder="johndoe@work.com"
                            value={email}
                            onChange={e => setEmail(e.target.value)}
                            required
                            disabled={loading}
                        />
                    </div>

                    {/* Password Input */}
                    <div style={styles.inputGroup}>
                        <label style={styles.label}>Password</label>
                        <input
                            type="password"
                            style={styles.input}
                            placeholder="**********"
                            value={password}
                            onChange={e => setPassword(e.target.value)}
                            required
                            disabled={loading}
                        />
                        <div style={styles.forgotPasswordContainer}>
                            <button
                                type="button"
                                style={styles.forgotPassword}
                                onClick={() => setIsForgotPassword(true)}
                                disabled={loading}
                            >
                                Forgot Password?
                            </button>
                        </div>
                    </div>

                    {/* Error Message */}
                    {errorMessage && (
                        <div style={styles.errorMessage}>
                            ⚠️ {errorMessage}
                        </div>
                    )}

                    {/* Submit Button */}
                    <button 
                        type="submit" 
                        style={{
                            ...styles.submitButton,
                            ...(loading && styles.submitButtonDisabled)
                        }}
                        disabled={loading}
                    >
                        {loading ? (
                            <span style={styles.loadingText}>
                                <span style={styles.spinner}></span>
                                Signing in...
                            </span>
                        ) : 'Submit'}
                    </button>

                    {/* Demo Login Button */}
                    <button
                        type="button"
                        onClick={handleDemoLogin}
                        style={styles.demoButton}
                        disabled={loading}
                    >
                        🎮 Try Demo Account
                    </button>

                    {/* Divider */}
                    <div style={styles.divider}>
                        <span style={styles.dividerText}>Or Sign in with</span>
                    </div>

                    {/* Social Login */}
                    <div style={styles.socialButtons}>
                        <button 
                            type="button" 
                            style={styles.socialButton}
                            onClick={handleGoogleLogin}
                            disabled={loading}
                        >
                            <span style={{...styles.socialIcon, color: '#DB4437'}}>G</span>
                            Google
                        </button>
                        <button 
                            type="button" 
                            style={styles.socialButton}
                            onClick={handleLinkedInLogin}
                            disabled={loading}
                        >
                            <span style={{...styles.socialIcon, color: '#0077B5'}}>in</span>
                            LinkedIn
                        </button>
                    </div>

                    {/* Sign Up Link */}
                    <div style={styles.signupContainer}>
                        <p style={styles.signupText}>
                            Not registered yet?{' '}
                            <Link to="/signup" style={styles.signupLink}>
                                Sign Up Now
                            </Link>
                        </p>
                    </div>
                </form>

                {/* Debug/Info Panel (visible in development) */}
                {process.env.NODE_ENV === 'development' && (
                    <div style={styles.debugPanel}>
                        <div style={styles.debugHeader}>
                            <small>🧪 Development Tools</small>
                        </div>
                        <div style={styles.debugButtons}>
                            <button
                                onClick={() => {
                                    setEmail('admin@example.com');
                                    setPassword('admin123');
                                    console.log('👨‍💼 Admin credentials loaded');
                                }}
                                style={styles.debugButton}
                            >
                                Load Admin
                            </button>
                            <button
                                onClick={() => {
                                    setEmail('user@example.com');
                                    setPassword('user123');
                                    console.log('👤 User credentials loaded');
                                }}
                                style={styles.debugButton}
                            >
                                Load User
                            </button>
                            <button
                                onClick={() => {
                                    localStorage.clear();
                                    console.log('🧹 Local storage cleared');
                                }}
                                style={styles.debugButton}
                            >
                                Clear Storage
                            </button>
                        </div>
                    </div>
                )}

                {/* Footer */}
                <div style={styles.footer}>
                    <p style={styles.copyright}>All rights reserved. © {new Date().getFullYear()}</p>
                    <div style={styles.footerLinks}>
                        <button 
                            type="button" 
                            style={styles.footerLink}
                            onClick={() => console.log('📄 Terms of Use clicked')}
                        >
                            Terms of Use
                        </button>
                        <span style={styles.separator}>•</span>
                        <button 
                            type="button" 
                            style={styles.footerLink}
                            onClick={() => console.log('🔒 Privacy Policy clicked')}
                        >
                            Privacy Policy
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

